function StructCombatResultInfo:CreateByPb(pb)
	self._reportId	    = pb.reportId
	self._combatType	= pb.combatType
	self._itemList		= pb.itemList
	self._winner	    = pb.winner
	self._startTime		= pb.startTime
	self._hurtCountA	= pb.hurtCountA
	self._hurtCountB	= pb.hurtCountB
	self._heroMvp		= pb.heroMvp
	self._hurtMax		= pb.hurtMax
	self._round 		= pb.round
	self._read			= pb.read
	self._targetName	= pb.targetName
	self._targetLevel	= pb.targetLevel
	self._monsterId		= pb.monsterId
	self._isOutLine		= pb.isOutLine
	self._battleNode	= pb.battleNode
	self._playTime		= pb.playTime
	self._serverId		= pb.serverId
	self._endlessInitNode = pb.endlessInitNode
	self._endlessMaxNode  = pb.endlessMaxNode
	self._cancel		= pb.cancel
	self._towerRefId	= pb.towerRefId
	self._wonderlandEventRefId = pb.wonderlandEventRefId
	self._preMaxHurt	= pb.preMaxHurt
	self._nextRewardHurt = pb.nextRewardHurt
	self._refId			= pb.refId
	self._isMonsterMVP  = pb.isMonsterMVP
	self._hpPercent		= pb.hpPercent
	self._output		= pb.output
	self._bear			= pb.bear
	self._cure			= pb.cure
	self._kill			= pb.kill

	if pb.attack then
		self._attack  	= gModelGeneral:SetPlayerInfo(pb.attack)
	end
	if pb.defense then
		self._defense  	= gModelGeneral:SetPlayerInfo(pb.defense)
	end

	if pb.attackHeros then
		self._attackHeros = gModelGeneral:SetCombatHeroData(pb.attackHeros)
	end

	if pb.defenseHeros then
		self._defenseHeros= gModelGeneral:SetCombatHeroData(pb.defenseHeros)
	end
end

